{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "# HDInsight Kafka Operations\nMonitor controller leadership, partition health, throughput, and JVM pressure from `HDInsightKafkaMetrics`."
      },
      "name": "Intro"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "HDInsightKafkaMetrics\n| where TimeGenerated > ago(24h)\n| where MetricName in ('ActiveControllerCount', 'OfflinePartitionsCount', 'UnderReplicatedPartitions')\n| summarize arg_max(TimeGenerated, MetricValue) by MetricName\n| project MetricName, LatestValue = todouble(MetricValue), LastUpdated = TimeGenerated\n| order by MetricName asc",
        "size": 0,
        "title": "Latest cluster state",
        "noDataMessage": "No Kafka cluster state metrics found in HDInsightKafkaMetrics.",
        "showRefreshButton": true,
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": [
          "__WORKSPACE_RESOURCE_ID__"
        ],
        "visualization": "table"
      },
      "name": "Latest cluster state"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "HDInsightKafkaMetrics\n| where TimeGenerated > ago(24h)\n| where MetricName in ('ActiveControllerCount', 'OfflinePartitionsCount', 'UnderReplicatedPartitions')\n| summarize ActiveControllerCount = avgif(todouble(MetricValue), MetricName == 'ActiveControllerCount'), OfflinePartitionsCount = avgif(todouble(MetricValue), MetricName == 'OfflinePartitionsCount'), UnderReplicatedPartitions = avgif(todouble(MetricValue), MetricName == 'UnderReplicatedPartitions') by bin(TimeGenerated, 5m)\n| order by TimeGenerated asc\n| render timechart",
        "size": 0,
        "title": "Cluster state over time",
        "noDataMessage": "No Kafka state trend data found in the selected workspace.",
        "showRefreshButton": true,
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": [
          "__WORKSPACE_RESOURCE_ID__"
        ],
        "visualization": "timechart"
      },
      "name": "Cluster state trend"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "HDInsightKafkaMetrics\n| where TimeGenerated > ago(24h)\n| where MetricName in ('MessagesInPerSec', 'BytesInPerSec', 'BytesOutPerSec')\n| summarize MessagesInPerSec = avgif(todouble(MetricValue), MetricName == 'MessagesInPerSec'), BytesInPerSec = avgif(todouble(MetricValue), MetricName == 'BytesInPerSec'), BytesOutPerSec = avgif(todouble(MetricValue), MetricName == 'BytesOutPerSec') by bin(TimeGenerated, 5m)\n| order by TimeGenerated asc\n| render timechart",
        "size": 0,
        "title": "Kafka throughput",
        "noDataMessage": "No Kafka throughput metrics found in HDInsightKafkaMetrics.",
        "showRefreshButton": true,
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": [
          "__WORKSPACE_RESOURCE_ID__"
        ],
        "visualization": "timechart"
      },
      "name": "Kafka throughput"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "HDInsightKafkaMetrics\n| where TimeGenerated > ago(24h)\n| where MetricNamespace == 'JVMMetrics'\n| where MetricName in ('jvm_memoryheapused', 'jvm_memoryheapmax')\n| summarize HeapUsed = avgif(todouble(MetricValue), MetricName == 'jvm_memoryheapused'), HeapMax = avgif(todouble(MetricValue), MetricName == 'jvm_memoryheapmax') by bin(TimeGenerated, 5m)\n| order by TimeGenerated asc\n| render timechart",
        "size": 0,
        "title": "Broker JVM heap",
        "noDataMessage": "No JVM heap metrics found in HDInsightKafkaMetrics.",
        "showRefreshButton": true,
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": [
          "__WORKSPACE_RESOURCE_ID__"
        ],
        "visualization": "timechart"
      },
      "name": "Broker JVM heap"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "let BrokerSelector = (tbl:(*)) {\n    tbl\n    | extend Broker = case(\n        isnotempty(tostring(column_ifexists('Computer', ''))), tostring(column_ifexists('Computer', '')),\n        isnotempty(tostring(column_ifexists('HostName', ''))), tostring(column_ifexists('HostName', '')),\n        isnotempty(tostring(column_ifexists('Host', ''))), tostring(column_ifexists('Host', '')),\n        isnotempty(tostring(column_ifexists('InstanceName', ''))), tostring(column_ifexists('InstanceName', '')),\n        'cluster')\n};\nlet LatestHeap = BrokerSelector(HDInsightKafkaMetrics\n    | where TimeGenerated > ago(24h)\n    | where MetricNamespace == 'JVMMetrics'\n    | where MetricName in ('jvm_memoryheapused', 'jvm_memoryheapmax'))\n| summarize arg_max(TimeGenerated, MetricValue) by Broker, MetricName\n| summarize HeapUsedBytes = maxif(todouble(MetricValue), MetricName == 'jvm_memoryheapused'), HeapMaxBytes = maxif(todouble(MetricValue), MetricName == 'jvm_memoryheapmax') by Broker;\nlet LatestReplication = BrokerSelector(HDInsightKafkaMetrics\n    | where TimeGenerated > ago(24h)\n    | where MetricName == 'UnderReplicatedPartitions')\n| summarize arg_max(TimeGenerated, MetricValue) by Broker\n| project Broker, UnderReplicatedPartitions = todouble(MetricValue);\nLatestHeap\n| join kind=fullouter LatestReplication on Broker\n| project Broker = coalesce(Broker, Broker1), HeapUsedMB = round(HeapUsedBytes / 1048576.0, 2), HeapMaxMB = round(HeapMaxBytes / 1048576.0, 2), UnderReplicatedPartitions = coalesce(UnderReplicatedPartitions, 0.0)\n| order by Broker asc",
        "size": 0,
        "title": "Latest broker state",
        "noDataMessage": "No broker-level metrics found in HDInsightKafkaMetrics.",
        "showRefreshButton": true,
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": [
          "__WORKSPACE_RESOURCE_ID__"
        ],
        "visualization": "table",
        "gridSettings": {
          "filter": true
        }
      },
      "name": "Latest broker state"
    }
  ],
  "isLocked": false,
  "fallbackResourceIds": [
    "__WORKSPACE_RESOURCE_ID__"
  ]
}

